class Solution {
    public int bestClosingTime(String customers) {
        int n = customers.length();
        int minPenalty = Integer.MAX_VALUE;
        int bestTime = 0;
        for (int i = 0; i <= n; i++) {
            int penalty = 0;
            for (int j = 0; j < n; j++) {
                if (j < i && customers.charAt(j) == 'N') penalty++;
                if (j >= i && customers.charAt(j) == 'Y') penalty++;
            }
            if (penalty < minPenalty) {
                minPenalty = penalty;
                bestTime = i;
            }
        }
        return bestTime;
    }
}
